args.sqlite_command:
DROP TABLE IF EXISTS J09B_temp;
CREATE TABLE J09B_temp AS
SELECT *
FROM decision_table
WHERE TOUR LIKE 'J09B%';
ALTER TABLE J09B_temp ADD COLUMN ENTSCHEIDUNG TEXT;

WITH haus_counts AS (
  SELECT HAUS, COUNT(EQUNR) AS eq_count
  FROM J09B_temp
  GROUP BY HAUS
)
UPDATE J09B_temp
SET ENTSCHEIDUNG = CASE
  WHEN (SELECT eq_count FROM haus_counts WHERE haus_counts.HAUS = J09B_temp.HAUS) < 3 THEN 'KSA'
  ELSE 'EVU'
END;

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0
   OR HOUSE_NUM1 BETWEEN 500 AND 599
   OR HOUSE_NUM1 BETWEEN 900 AND 999
   OR CITY2 IN ('Wiblingwerde', 'Breckerfeld');

ALTER TABLE J09B_temp ADD COLUMN "Meter Reading (MR) Doc. No." TEXT;
ALTER TABLE J09B_temp ADD COLUMN TITLE TEXT;
ALTER TABLE J09B_temp ADD COLUMN FORENAME TEXT;
ALTER TABLE J09B_temp ADD COLUMN SURNAME TEXT;
ALTER TABLE J09B_temp ADD COLUMN STREET TEXT;
ALTER TABLE J09B_temp ADD COLUMN STREETNO TEXT;
ALTER TABLE J09B_temp ADD COLUMN FINAL_CITY1 TEXT;
ALTER TABLE J09B_temp ADD COLUMN FINAL_CITY2 TEXT;
ALTER TABLE J09B_temp ADD COLUMN FINAL_POST_CODE1 INTEGER;
ALTER TABLE J09B_temp ADD COLUMN EMAIL TEXT;

UPDATE J09B_temp
SET "Meter Reading (MR) Doc. No." = (
  SELECT eablg."Meter Reading (MR) Doc. No."
  FROM eablg
  WHERE eablg.Installation = J09B_temp.ANLAGE
  LIMIT 1
);

UPDATE J09B_temp
SET TITLE = COALESCE((SELECT s.TITLE FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.TITLE FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    FORENAME = COALESCE((SELECT s.FORENAME FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.FORENAME FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    SURNAME = COALESCE((SELECT s.SURNAME FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.SURNAME FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    STREET = COALESCE((SELECT s.STREET FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.STREET FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    STREETNO = COALESCE((SELECT s.STREETNO FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.STREETNO FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    FINAL_CITY1 = COALESCE((SELECT s.CITY1 FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.CITY1 FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    FINAL_CITY2 = COALESCE((SELECT s.CITY2 FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.CITY2 FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    FINAL_POST_CODE1 = COALESCE((SELECT s.POST_CODE1 FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.POST_CODE1 FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1)),
    EMAIL = COALESCE((SELECT s.EMAIL FROM sales_master s WHERE s.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT n.EMAIL FROM net_master n WHERE n.EQUNR = J09B_temp.EQUNR LIMIT 1));

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
  SELECT e1.EQUNR
  FROM eabl e1
  JOIN eabl e2 ON e1.EQUNR = e2.EQUNR
  WHERE e1.ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr(e1."Record created on", 1, 4) = '2024'
    AND e2.ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr(e2."Record created on", 1, 4) = '2023'
);
